fields.collector:
$sbKey = 'HKLM:\SYSTEM\CurrentControlSet\Control\SecureBoot'
$svcKey = "$sbKey\Servicing"
$daKey = "$svcKey\DeviceAttributes"
$reg = {
    param($Path, $Name)
    try { (Get-ItemProperty -Path $Path -Name $Name -ErrorAction Stop).$Name } catch { $null }
}
$hex = { param($v) if ($null -ne $v) { '0x{0:X}' -f $v } else { $null } }
$o = [ordered]@{}
try { $o['SecureBootEnabled'] = [bool](Confirm-SecureBootUEFI -ErrorAction Stop) } catch { $o['SecureBootEnabled'] = $null }
$o['AvailableUpdates'] = & $hex (& $reg $sbKey 'AvailableUpdates')
$o['AvailableUpdatesPolicy'] = & $hex (& $reg $sbKey 'AvailableUpdatesPolicy')
$o['HighConfidenceOptOut'] = & $reg $sbKey 'HighConfidenceOptOut'
$o['MicrosoftUpdateManagedOptIn'] = & $reg $sbKey 'MicrosoftUpdateManagedOptIn'
$o['UEFICA2023Status'] = & $reg $svcKey 'UEFICA2023Status'
$o['UEFICA2023Error'] = & $reg $svcKey 'UEFICA2023Error'
$o['UEFICA2023ErrorEvent'] = & $reg $svcKey 'UEFICA2023ErrorEvent'
$o['OEMManufacturerName'] = & $reg $daKey 'OEMManufacturerName'
$o['OEMModelSystemFamily'] = & $reg $daKey 'OEMModelSystemFamily'
$o['OEMModelNumber'] = & $reg $daKey 'OEMModelNumber'
$o['FirmwareVersion'] = & $reg $daKey 'FirmwareVersion'
$o['FirmwareReleaseDate'] = & $reg $daKey 'FirmwareReleaseDate'
$cau = & $reg $daKey 'CanAttemptUpdateAfter'
if ($cau -is [byte[]]) { try { $o['CanAttemptUpdateAfter'] = [DateTime]::FromFileTime([BitConverter]::ToInt64($cau, 0)).ToUniversalTime().ToString('o') } catch { $o['CanAttemptUpdateAfter'] = $null } } elseif ($cau) { try { $o['CanAttemptUpdateAfter'] = [DateTime]::FromFileTime([int64]$cau).ToUniversalTime().ToString('o') } catch { $o['CanAttemptUpdateAfter'] = "$cau" } } else { $o['CanAttemptUpdateAfter'] = $null }
$db2023 = 0; $kek2023 = 0; $tp2011 = 0; $tpReq = 0; $tp2023 = 0; $tpOrom = 0
try {
    $dbStr = [Text.Encoding]::ASCII.GetString((Get-SecureBootUEFI db -ErrorAction Stop).bytes)
    if ($dbStr -match 'Windows UEFI CA 2023') { $db2023 = 1 }
    if ($dbStr -match 'Microsoft Corporation UEFI CA 2011') { $tp2011 = 1; $tpReq = 1 }
    if ($dbStr -match 'Microsoft UEFI CA 2023' -and $tpReq -eq 1) { $tp2023 = 1 }
    if ($dbStr -match 'Microsoft Option ROM UEFI CA 2023' -and $tpReq -eq 1) { $tpOrom = 1 }
} catch { }
try {
    $kekStr = [Text.Encoding]::ASCII.GetString((Get-SecureBootUEFI kek -ErrorAction Stop).bytes)
    if ($kekStr -match 'Microsoft Corporation KEK 2K CA 2023') { $kek2023 = 1 }
} catch { }
if ($db2023 -eq 0 -or $kek2023 -eq 0) { $tp2023 = 0; $tpOrom = 0 }
$o['FirstPartyDB2023Updated'] = $db2023
$o['FirstPartyKEK2023Updated'] = $kek2023
$o['ThirdParty2011CAPresent'] = $tp2011
$o['ThirdParty2023CertsRequired'] = $tpReq
$o['ThirdParty2023CertUpdated'] = $tp2023
$o['ThirdPartyOptionRom2023CertUpdated'] = $tpOrom
try { $task = schtasks.exe /Query /TN '\Microsoft\Windows\PI\Secure-Boot-Update' /FO CSV 2>&1 | ConvertFrom-Csv; if ($task) { $o['SecureBootTaskStatus'] = $task.Status; $o['SecureBootTaskEnabled'] = ($task.Status -eq 'Ready' -or $task.Status -eq 'Running') } else { $o['SecureBootTaskStatus'] = 'NotFound'; $o['SecureBootTaskEnabled'] = $false } } catch { $o['SecureBootTaskStatus'] = 'Error'; $o['SecureBootTaskEnabled'] = $false }
try { $ev = @(Get-WinEvent -FilterHashtable @{ LogName = 'System'; ID = @(1795, 1796, 1800, 1801, 1802, 1803, 1808) } -MaxEvents 50 -ErrorAction Stop); $latest = $ev | Sort-Object TimeCreated -Descending | Select-Object -First 1; $o['LatestEventId'] = if ($latest) { $latest.Id } else { $null }; $o['Event1801Count'] = @($ev | Where-Object { $_.Id -eq 1801 }).Count; $o['Event1808Count'] = @($ev | Where-Object { $_.Id -eq 1808 }).Count; $o['RebootPending'] = @($ev | Where-Object { $_.Id -eq 1800 }).Count -gt 0; $o['MissingKEK'] = @($ev | Where-Object { $_.Id -eq 1803 }).Count -gt 0 } catch { $o['LatestEventId'] = $null; $o['Event1801Count'] = 0; $o['Event1808Count'] = 0; $o['RebootPending'] = $false; $o['MissingKEK'] = $false }
[pscustomobject]$o
